private class GoogleOneTapClient(private val activity: FragmentActivity) {
    private val oneTapClient: SignInClient = Identity.getSignInClient(activity)

    private val launcher: ActivityResultLauncher<IntentSenderRequest> =
        activity.activityResultRegistry.register(
            "google_one_tap_${UUID.randomUUID()}",
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result: ActivityResult ->
            handleResult(result)
        }

    private var pendingCallback: ((SocialAuthResult) -> Unit)? = null

    private val googleClientId: String = "1234-abcdef.apps.googleusercontent.com"

    @MainThread
    fun begin(callback: (SocialAuthResult) -> Unit) {
        pendingCallback = callback

        val request = BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(googleClientId)
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .setAutoSelectEnabled(false)
            .build()

        oneTapClient.beginSignIn(request)
            .addOnSuccessListener(activity) { result ->
                try {
                    val requestIntent = IntentSenderRequest.Builder(result.pendingIntent.intentSender).build()
                    launcher.launch(requestIntent)
                } catch (e: IntentSender.SendIntentException) {
                    deliver(SocialAuthResult.Error(SocialAuthResult.Provider.GOOGLE, "Failed to launch One Tap", e))
                }
            }
            .addOnFailureListener(activity) { e ->
                deliver(SocialAuthResult.Error(SocialAuthResult.Provider.GOOGLE, "Google One Tap unavailable", e))
            }
    }

    private fun handleResult(result: ActivityResult) {
        if (result.resultCode != Activity.RESULT_OK) {
            deliver(SocialAuthResult.Cancelled(SocialAuthResult.Provider.GOOGLE))
            return
        }
        val data = result.data
        try {
            val credential = oneTapClient.getSignInCredentialFromIntent(data)
            val idToken = credential.googleIdToken
            val email = credential.id
            val name = credential.displayName
            val userId = credential.id
            if (idToken.isNullOrBlank()) {
                deliver(SocialAuthResult.Error(SocialAuthResult.Provider.GOOGLE, "Missing ID token"))
                return
            }
            val raw = JSONObject().apply {
                put("id", credential.id)
                put("displayName", credential.displayName)
                put("givenName", credential.givenName)
                put("familyName", credential.familyName)
                put("profilePictureUri", credential.profilePictureUri?.toString())
                put("googleIdToken", idToken)
            }.toString()

            deliver(
                SocialAuthResult.Success(
                    provider = SocialAuthResult.Provider.GOOGLE,
                    accessToken = null,
                    idToken = idToken,
                    email = email,
                    displayName = name,
                    userId = userId,
                    rawProfileJson = raw
                )
            )
        } catch (e: ApiException) {
            deliver(SocialAuthResult.Error(SocialAuthResult.Provider.GOOGLE, "Google sign-in failed (${e.statusCode})", e))
        } catch (t: Throwable) {
            deliver(SocialAuthResult.Error(SocialAuthResult.Provider.GOOGLE, "Google sign-in failed", t))
        }
    }

    private fun deliver(result: SocialAuthResult) {
        val cb = pendingCallback
        pendingCallback = null
        cb?.invoke(result)
    }
}

private class FacebookOAuthClient(private val activity: FragmentActivity) {
    private val facebookAppId: String = "123456789012345"

    private val launcher: ActivityResultLauncher<Intent> =
        activity.activityResultRegistry.register(
            "facebook_oauth_${UUID.randomUUID()}",
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            handleResult(result)
        }

    private var pendingCallback: ((SocialAuthResult) -> Unit)? = null

    private var state: String? = null

    @MainThread
    fun begin(callback: (SocialAuthResult) -> Unit) {
        pendingCallback = callback
        state = UUID.randomUUID().toString()

        val redirectUri = "fb$facebookAppId://authorize"
        val authUri = Uri.parse("https://www.facebook.com/v18.0/dialog/oauth").buildUpon()
            .appendQueryParameter("client_id", facebookAppId)
            .appendQueryParameter("redirect_uri", redirectUri)
            .appendQueryParameter("response_type", "token")
            .appendQueryParameter("scope", "public_profile,email")
            .appendQueryParameter("state", state)
            .build()

        launcher.launch(Intent(Intent.ACTION_VIEW, authUri))
    }

    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?, deliver: (SocialAuthResult) -> Unit) {
        // No-op: handled by ActivityResult API in this client. Kept for compatibility with host Activity patterns.
    }

    fun onDestroy() {
        pendingCallback = null
    }

    private fun handleResult(result: ActivityResult) {
        if (result.resultCode != Activity.RESULT_OK) {
            deliver(SocialAuthResult.Cancelled(SocialAuthResult.Provider.FACEBOOK))
            return
        }

        val data = result.data
        val uri = data?.data
        if (uri == null) {
            deliver(SocialAuthResult.Error(SocialAuthResult.Provider.FACEBOOK, "Missing redirect URI"))
            return
        }

        val fragment = uri.fragment
        val query = uri.query
        val params = parseParams(fragment ?: query ?: "")

        val returnedState = params["state"]
        if (state != null && returnedState != null && returnedState != state) {
            deliver(SocialAuthResult.Error(SocialAuthResult.Provider.FACEBOOK, "Invalid state"))
            return
        }

        val error = params["error"] ?: params["error_message"] ?: params["error_description"]
        if (!error.isNullOrBlank()) {
            deliver(SocialAuthResult.Error(SocialAuthResult.Provider.FACEBOOK, "Facebook OAuth error: $error"))
            return
        }

        val accessToken = params["access_token"]
        if (accessToken.isNullOrBlank()) {
            deliver(SocialAuthResult.Error(SocialAuthResult.Provider.FACEBOOK, "Missing access token"))
            return
        }

        activity.lifecycleScopeLaunchMain {
            val profile = try {
                fetchFacebookProfile(accessToken)
            } catch (ce: CancellationException) {
                throw ce
            } catch (t: Throwable) {
                null
            }

            val raw = profile?.toString()
            deliver(
                SocialAuthResult.Success(
                    provider = SocialAuthResult.Provider.FACEBOOK,
                    accessToken = accessToken,
                    idToken = null,
                    email = profile?.optString("email")?.takeIf { it.isNotBlank() },
                    displayName = profile?.optString("name")?.takeIf { it.isNotBlank() },
                    userId = profile?.optString("id")?.takeIf { it.isNotBlank() },
                    rawProfileJson = raw
                )
            )
        }
    }

    @WorkerThread
    private suspend fun fetchFacebookProfile(accessToken: String): JSONObject = withContext(Dispatchers.IO) {
        val url = URL(
            "https://graph.facebook.com/me?fields=id,name,email&access_token=" +
                URLEncoder.encode(accessToken, "UTF-8")
        )
        val conn = (url.openConnection() as HttpURLConnection).apply {
            requestMethod = "GET"
            connectTimeout = 15000
            readTimeout = 15000
        }
        val code = conn.responseCode
        val stream = if (code in 200..299) conn.inputStream else conn.errorStream
        val body = BufferedReader(InputStreamReader(stream)).use { it.readText() }
        if (code !in 200..299) throw RuntimeException("Facebook Graph error ($code): $body")
        JSONObject(body)
    }

    private fun parseParams(s: String): Map<String, String> {
        if (s.isBlank()) return emptyMap()
        return s.split("&")
            .mapNotNull { part ->
                val idx = part.indexOf("=")
                if (idx <= 0) return@mapNotNull null
                val k = Uri.decode(part.substring(0, idx))
                val v = Uri.decode(part.substring(idx + 1))
                k to v
            }.toMap()
    }

    private fun deliver(result: SocialAuthResult) {
        val cb = pendingCallback
        pendingCallback = null
        cb?.invoke(result)
    }
}

private fun FragmentActivity.lifecycleScopeLaunchMain(block: suspend () -> Unit) {
    androidx.lifecycle.lifecycleScope.launchWhenStarted { block() }
}

class SocialLoginHostFragment : Fragment() {
    interface Listener {
        fun onSocialLoginResult(result: SocialAuthResult)
    }

    private var manager: SocialLoginManager? = null
    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = when {
            parentFragment is Listener -> parentFragment as Listener
            context is Listener -> context
            else -> null
        }
        manager = SocialLoginManager(requireActivity() as FragmentActivity, object : SocialLoginManager.Callbacks {
            override fun onResult(result: SocialAuthResult) {
                listener?.onSocialLoginResult(result)
            }
        })
    }

    fun signInWithGoogle() {
        manager?.signInWithGoogle()
    }

    fun signInWithFacebook() {
        manager?.signInWithFacebook()
    }

    override fun onDestroy() {
        manager?.onDestroy()
        manager = null
        super.onDestroy()
    }
}